/**
 * Builds a fixed set of empty form rows for URL-encoded form submission.
 * @param {string[]} hints
 * @returns {Array<{ id: number, key: string, value: string }>}
 */
function createRows(hints) {
  return hints.map((hint, index) => ({
    id: Date.now() + index,
    key: hint,
    value: '',
  }))
}

// Generated by GitHub Copilot
/**
 * Converts form rows into a URLSearchParams payload for Spring model binding.
 * Empty keys are ignored to avoid sending invalid form fields.
 * @param {Array<{ key: string, value: string }>} rows
 * @returns {URLSearchParams}
 */
function buildFormPayload(rows) {
  const payload = new URLSearchParams()

  for (const row of rows) {
    const key = row.key.trim()
    if (key.length > 0) {
      payload.append(key, row.value)
    }
  }

  return payload
}

