/**
 * Formats a table cell value including nested patient objects.
 * @param {unknown} value
 * @param {string} column
 * @returns {string}
 */
function formatCellValue(value, column) {
  if (value === null || value === undefined) {
    return ''
  }

  if (typeof value === 'object') {
    if (column === 'patient' && !Array.isArray(value)) {
      const patient = /** @type {Record<string, unknown>} */ (value)
      const patientParts = [
        patient.patientId ? `ID: ${String(patient.patientId)}` : '',
        patient.patientName ? `Name: ${String(patient.patientName)}` : '',
        patient.age ? `Age: ${String(patient.age)}` : '',
        patient.gender ? `Gender: ${String(patient.gender)}` : '',
        patient.contactNumber ? `Contact: ${String(patient.contactNumber)}` : '',
      ].filter(Boolean)

      return patientParts.join(' | ')
    }

    return JSON.stringify(value)
  }

  return String(value)
}

