/**
 * Generic page for POSTing URL-encoded form fields to a Spring controller.
 * @param {{ title: string, endpoint: string, description: string, hints: string[] }} props
 * @returns {JSX.Element}
 */
function EntityFormPage({ title, endpoint, description, hints }) {
  const baseUrl = import.meta.env.VITE_API_BASE_URL ?? 'http://localhost:8090'
  const [rows, setRows] = useState(() => createRows(hints))
  const [status, setStatus] = useState('')
  const [isSaving, setIsSaving] = useState(false)

  // Generated by GitHub Copilot
  /**
   * Updates the entered value for a fixed form field.
   * @param {number} id
   * @param {string} value
   */
  function updateRow(id, value) {
    setRows((current) =>
      current.map((row) => (row.id === id ? { ...row, value } : row)),
    )
  }

  // Generated by GitHub Copilot
  /**
   * Resets the form after a successful save.
   */
  function resetRows() {
    setRows(createRows(hints))
  }

  // Generated by GitHub Copilot
  /**
   * Sends the URL-encoded payload to the configured controller save endpoint.
   * @param {import('react').FormEvent<HTMLFormElement>} event
   */
  async function handleSubmit(event) {
    event.preventDefault()
    setIsSaving(true)
    setStatus('Saving...')

    try {
      const response = await fetch(buildEndpoint(baseUrl, endpoint), {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded;charset=UTF-8',
        },
        body: buildFormPayload(rows).toString(),
      })

      const bodyMessage = await parseResponseBody(response)
      if (!response.ok) {
        throw new Error(`Save failed: ${bodyMessage}`)
      }

      setStatus(bodyMessage || 'Saved successfully.')
      resetRows()
    } catch (error) {
      setStatus(toFriendlyError(error))
    } finally {
      setIsSaving(false)
    }
  }

  return (
    <section className="page-card" aria-labelledby={`${title}-heading`}>
      <div className="page-card__header">
        <h2 id={`${title}-heading`}>{title}</h2>
      </div>

      <form onSubmit={handleSubmit} className="entity-form">
        <div className="field-grid" role="group" aria-label={`${title} form fields`}>
          {rows.map((row, index) => (
            <div className="field-row" key={row.id}>
              <label htmlFor={`${title}-value-${row.id}`}>{row.key}</label>
              <input
                id={`${title}-value-${row.id}`}
                type="text"
                value={row.value}
                onChange={(event) => updateRow(row.id, event.target.value)}
                placeholder={`Enter ${row.key}`}
              />
            </div>
          ))}
        </div>

        <div className="form-footer">
          <button className="primary-btn" type="submit" disabled={isSaving}>
            Save
          </button>
          {status ? <p className="status-text" role="status">{status}</p> : null}
        </div>
      </form>
    </section>
  )
}

