/**
 * Generic page for displaying a GET list endpoint in a table.
 * @param {{ title: string, endpoint: string, description: string, emptyMessage: string, hiddenColumns?: string[] }} props
 * @returns {JSX.Element}
 */
function EntityListPage({ title, endpoint, description, emptyMessage, hiddenColumns = [] }) {
  const baseUrl = import.meta.env.VITE_API_BASE_URL ?? 'http://localhost:8090'
  const [items, setItems] = useState([])
  const [status, setStatus] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const columns = deriveColumns(items).filter((column) => !hiddenColumns.includes(column))

  // Generated by GitHub Copilot
  /**
   * Fetches the list endpoint and updates the table state.
   */
  async function fetchItems() {
    setIsLoading(true)
    setStatus('Loading...')

    try {
      const response = await fetch(buildEndpoint(baseUrl, endpoint))
      if (!response.ok) {
        throw new Error(`Request failed with status ${response.status}`)
      }

      const data = await response.json()
      setItems(Array.isArray(data) ? data : [])
      setStatus('Data loaded.')
    } catch (error) {
      setStatus(toFriendlyError(error))
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    fetchItems()
  }, [])

  return (
    <section className="page-card" aria-labelledby={`${title}-heading`}>
      <div className="list-header">
        <div>
          <h2 id={`${title}-heading`}>{title}</h2>
        </div>
        <button className="secondary-btn" type="button" onClick={fetchItems} disabled={isLoading}>
          Refresh
        </button>
      </div>

      {status ? <p className="status-text" role="status">{status}</p> : null}

      {items.length === 0 ? (
        <p className="empty-state">{emptyMessage}</p>
      ) : (
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                {columns.map((column) => (
                  <th key={column} scope="col">{column}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {items.map((item, rowIndex) => (
                <tr key={`${title}-${rowIndex}`}>
                  {columns.map((column) => (
                    <td key={`${rowIndex}-${column}`}>{formatCellValue(item[column], column)}</td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </section>
  )
}

